# ClickGraphError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class ClickGraphError(Exception):
    pass

_UniffiTempClickGraphError = ClickGraphError

class ClickGraphError:  # type: ignore
    class DatabaseError(_UniffiTempClickGraphError):
        def __init__(self, msg):
            super().__init__(", ".join([
                "msg={!r}".format(msg),
            ]))
            self.msg = msg

        def __repr__(self):
            return "ClickGraphError.DatabaseError({})".format(str(self))
    _UniffiTempClickGraphError.DatabaseError = DatabaseError # type: ignore
    class QueryError(_UniffiTempClickGraphError):
        def __init__(self, msg):
            super().__init__(", ".join([
                "msg={!r}".format(msg),
            ]))
            self.msg = msg

        def __repr__(self):
            return "ClickGraphError.QueryError({})".format(str(self))
    _UniffiTempClickGraphError.QueryError = QueryError # type: ignore
    class ExportError(_UniffiTempClickGraphError):
        def __init__(self, msg):
            super().__init__(", ".join([
                "msg={!r}".format(msg),
            ]))
            self.msg = msg

        def __repr__(self):
            return "ClickGraphError.ExportError({})".format(str(self))
    _UniffiTempClickGraphError.ExportError = ExportError # type: ignore
    class ValidationError(_UniffiTempClickGraphError):
        def __init__(self, msg):
            super().__init__(", ".join([
                "msg={!r}".format(msg),
            ]))
            self.msg = msg

        def __repr__(self):
            return "ClickGraphError.ValidationError({})".format(str(self))
    _UniffiTempClickGraphError.ValidationError = ValidationError # type: ignore

ClickGraphError = _UniffiTempClickGraphError # type: ignore
del _UniffiTempClickGraphError


class _UniffiConverterTypeClickGraphError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return ClickGraphError.DatabaseError(
                _UniffiConverterString.read(buf),
            )
        if variant == 2:
            return ClickGraphError.QueryError(
                _UniffiConverterString.read(buf),
            )
        if variant == 3:
            return ClickGraphError.ExportError(
                _UniffiConverterString.read(buf),
            )
        if variant == 4:
            return ClickGraphError.ValidationError(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, ClickGraphError.DatabaseError):
            _UniffiConverterString.check_lower(value.msg)
            return
        if isinstance(value, ClickGraphError.QueryError):
            _UniffiConverterString.check_lower(value.msg)
            return
        if isinstance(value, ClickGraphError.ExportError):
            _UniffiConverterString.check_lower(value.msg)
            return
        if isinstance(value, ClickGraphError.ValidationError):
            _UniffiConverterString.check_lower(value.msg)
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, ClickGraphError.DatabaseError):
            buf.write_i32(1)
            _UniffiConverterString.write(value.msg, buf)
        if isinstance(value, ClickGraphError.QueryError):
            buf.write_i32(2)
            _UniffiConverterString.write(value.msg, buf)
        if isinstance(value, ClickGraphError.ExportError):
            buf.write_i32(3)
            _UniffiConverterString.write(value.msg, buf)
        if isinstance(value, ClickGraphError.ValidationError):
            buf.write_i32(4)
            _UniffiConverterString.write(value.msg, buf)





