        v: "bool"

        def __init__(self,v: "bool"):
            self.v = v

        def __str__(self):
            return "Value.BOOL(v={})".format(self.v)

        def __eq__(self, other):
            if not other.is_BOOL():
                return False
            if self.v != other.v:
                return False
            return True
    
