# Connection is a Rust-only trait - it's a wrapper around a Rust implementation.
class Connection():
    _pointer: ctypes.c_void_p
    
    def __init__(self, *args, **kwargs):
        raise ValueError("This class has no default constructor")

    def __del__(self):
        # In case of partial initialization of instances.
        pointer = getattr(self, "_pointer", None)
        if pointer is not None:
            _uniffi_rust_call(_UniffiLib.uniffi_clickgraph_ffi_fn_free_connection, pointer)

    def _uniffi_clone_pointer(self):
        return _uniffi_rust_call(_UniffiLib.uniffi_clickgraph_ffi_fn_clone_connection, self._pointer)

    # Used by alternative constructors or any methods which return this type.
    @classmethod
    def _make_instance_(cls, pointer):
        # Lightly yucky way to bypass the usual __init__ logic
        # and just create a new instance with the required pointer.
        inst = cls.__new__(cls)
        inst._pointer = pointer
        return inst


    def create_edge(self, edge_type: "str",from_id: "str",to_id: "str",properties: "dict[str, Value]") -> None:
        """
        Create an edge between two nodes.
        """

        _UniffiConverterString.check_lower(edge_type)
        
        _UniffiConverterString.check_lower(from_id)
        
