    def check_lower(value: QueryResult):
        if not isinstance(value, QueryResult):
            raise TypeError("Expected QueryResult instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: QueryResultProtocol):
        if not isinstance(value, QueryResult):
            raise TypeError("Expected QueryResult instance, {} found".format(type(value).__name__))
        return value._uniffi_clone_pointer()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer):
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw pointer value was null")
        return cls.lift(ptr)

    @classmethod
    def write(cls, value: QueryResultProtocol, buf: _UniffiRustBuffer):
        buf.write_u64(cls.lower(value))

